<template>
	<div class="bg-white rounded-lg border border-gray-200 overflow-hidden">
		<!-- Loading skeleton -->
		<div v-if="loading" class="p-6 space-y-3">
			<div v-for="i in 5" :key="i" class="h-12 bg-gray-100 rounded animate-pulse" />
		</div>

		<!-- Empty state -->
		<div
			v-else-if="!timesheets.length"
			class="flex flex-col items-center justify-center py-16 text-gray-400"
		>
			<Clock class="w-10 h-10 mb-2" />
			<p class="text-sm">{{ translate("No timesheets found for the selected period.") }}</p>
		</div>

		<!-- Table -->
		<div v-else class="overflow-x-auto">
			<table class="w-full text-sm">
				<thead class="bg-gray-50 border-b border-gray-200">
					<tr>
						<th
							class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Employee") }}
						</th>
						<th
							class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Period") }}
						</th>
						<th
							class="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Hours") }}
						</th>
						<th
							class="px-4 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Is Billable") }}
						</th>
						<th
							class="px-4 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Status") }}
						</th>
						<th
							class="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Actions") }}
						</th>
					</tr>
				</thead>
				<tbody class="divide-y divide-gray-100">
					<tr
						v-for="ts in timesheets"
						:key="ts.name"
						class="hover:bg-gray-50 transition-colors"
					>
						<!-- Employee -->
						<td class="px-4 py-3">
							<div class="font-medium text-gray-900">{{ ts.employee_name }}</div>
							<div class="text-xs text-gray-400">{{ ts.employee }}</div>
						</td>

						<!-- Period -->
						<td class="px-4 py-3 text-gray-600">
							<div>{{ formatDate(ts.start_date) }}</div>
							<div
								v-if="ts.end_date && ts.end_date !== ts.start_date"
								class="text-xs text-gray-400"
							>
								→ {{ formatDate(ts.end_date) }}
							</div>
						</td>

						<!-- Hours -->
						<td class="px-4 py-3 text-right font-mono font-medium text-gray-900">
							{{ (ts.total_hours || 0).toFixed(1) }}h
						</td>

						<!-- Is Billable checkbox -->
						<td class="px-4 py-3 text-center">
							<input
								type="checkbox"
								:checked="(ts.total_billable_hours || 0) > 0"
								:disabled="ts.docstatus !== 0 || !!updatingBillable[ts.name]"
								@change="onBillableChange(ts, $event.target.checked)"
								class="w-4 h-4 rounded border-gray-300 text-blue-600 cursor-pointer disabled:cursor-not-allowed disabled:opacity-50"
								:title="
									ts.docstatus !== 0
										? translate(
												'Cannot change billable status after submission'
										  )
										: translate('Toggle billable')
								"
							/>
						</td>

						<!-- Status badge -->
						<td class="px-4 py-3 text-center">
							<span
								:class="statusBadgeClass(ts.status)"
								class="px-2 py-0.5 rounded-full text-xs font-medium"
							>
								{{ translate(ts.status) }}
							</span>
						</td>

						<!-- Actions -->
						<td class="px-4 py-3">
							<div class="flex items-center justify-end gap-2">
								<!-- Submit (approve) - only for Draft -->
								<button
									v-if="ts.docstatus === 0"
									@click="$emit('submit', ts.name)"
									class="flex items-center gap-1 px-2 py-1 text-xs text-green-700 bg-green-50 border border-green-200 rounded hover:bg-green-100 transition-colors"
									:title="translate('Submit')"
								>
									<CheckCircle class="w-3.5 h-3.5" />
									{{ translate("Submit") }}
								</button>

								<!-- Cancel - only for Submitted -->
								<button
									v-if="ts.docstatus === 1"
									@click="$emit('cancel', ts.name)"
									class="flex items-center gap-1 px-2 py-1 text-xs text-red-700 bg-red-50 border border-red-200 rounded hover:bg-red-100 transition-colors"
									:title="translate('Cancel')"
								>
									<XCircle class="w-3.5 h-3.5" />
									{{ translate("Cancel") }}
								</button>

								<!-- Open in ERPNext -->
								<a
									:href="`/app/timesheet/${ts.name}`"
									target="_blank"
									rel="noopener noreferrer"
									class="flex items-center gap-1 px-2 py-1 text-xs text-blue-700 bg-blue-50 border border-blue-200 rounded hover:bg-blue-100 transition-colors"
									:title="translate('Open')"
								>
									<ExternalLink class="w-3.5 h-3.5" />
									{{ translate("Open") }}
								</a>
							</div>
						</td>
					</tr>
				</tbody>
			</table>
		</div>

		<!-- Footer: total count -->
		<div
			v-if="timesheets.length"
			class="px-4 py-2 border-t border-gray-100 text-xs text-gray-400 flex justify-between"
		>
			<span>{{ timesheets.length }} {{ translate("timesheets") }}</span>
			<span>{{ translate("Total") }}: {{ totalHours.toFixed(1) }}h</span>
		</div>
	</div>
</template>

<script setup>
import { computed, reactive } from "vue";
import { Clock, CheckCircle, XCircle, ExternalLink } from "lucide-vue-next";

const realWindow = typeof globalThis !== "undefined" ? globalThis.window : undefined;
const translate = (text) => {
	return typeof realWindow !== "undefined" && typeof realWindow.__ === "function"
		? realWindow.__(text)
		: text;
};

const props = defineProps({
	timesheets: { type: Array, default: () => [] },
	loading: { type: Boolean, default: false },
});

const emit = defineEmits(["submit", "cancel", "set-billable"]);

const updatingBillable = reactive({});

const totalHours = computed(() =>
	props.timesheets.reduce((sum, ts) => sum + (ts.total_hours || 0), 0)
);

async function onBillableChange(ts, checked) {
	updatingBillable[ts.name] = true;
	try {
		emit("set-billable", { name: ts.name, isBillable: checked });
	} finally {
		updatingBillable[ts.name] = false;
	}
}

function formatDate(dateStr) {
	if (!dateStr) return "—";
	const d = new Date(dateStr);
	return d.toLocaleDateString("pl-PL", { day: "2-digit", month: "2-digit", year: "numeric" });
}

function statusBadgeClass(status) {
	const map = {
		Draft: "bg-yellow-100 text-yellow-800",
		Submitted: "bg-green-100 text-green-800",
		Cancelled: "bg-red-100 text-red-800",
		Billed: "bg-blue-100 text-blue-800",
		Payslip: "bg-purple-100 text-purple-800",
		Completed: "bg-gray-100 text-gray-700",
		"Partially Billed": "bg-indigo-100 text-indigo-800",
	};
	return map[status] || "bg-gray-100 text-gray-600";
}
</script>
