<template>
	<div class="bg-white rounded-lg border border-gray-200 overflow-hidden">
		<!-- Loading skeleton -->
		<div v-if="loading" class="p-6 space-y-3">
			<div v-for="i in 4" :key="i" class="h-10 bg-gray-100 rounded animate-pulse" />
		</div>

		<!-- All good -->
		<div
			v-else-if="!employees.length"
			class="flex flex-col items-center justify-center py-16 text-green-600"
		>
			<CheckCircle class="w-12 h-12 mb-2" />
			<p class="text-sm font-medium">
				{{ translate("All employees have timesheets for the selected period.") }}
			</p>
		</div>

		<!-- Missing employees table -->
		<div v-else class="overflow-x-auto">
			<!-- Info banner -->
			<div
				class="px-4 py-3 bg-orange-50 border-b border-orange-100 flex items-center gap-2 text-sm text-orange-700"
			>
				<AlertTriangle class="w-4 h-4 flex-shrink-0" />
				<span>
					{{ employees.length }}
					{{ translate("employee(s) have no timesheet between") }}
					{{ formatDate(startDate) }} – {{ formatDate(endDate) }}.
				</span>
			</div>

			<table class="w-full text-sm">
				<thead class="bg-gray-50 border-b border-gray-200">
					<tr>
						<th
							class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Employee") }}
						</th>
						<th
							class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Department") }}
						</th>
					</tr>
				</thead>
				<tbody class="divide-y divide-gray-100">
					<tr v-for="emp in employees" :key="emp.name" class="hover:bg-gray-50">
						<td class="px-4 py-3">
							<div class="font-medium text-gray-900">{{ emp.employee_name }}</div>
							<div class="text-xs text-gray-400">{{ emp.name }}</div>
						</td>
						<td class="px-4 py-3 text-gray-600">{{ emp.department || "—" }}</td>
					</tr>
				</tbody>
			</table>
		</div>
	</div>
</template>

<script setup>
import { CheckCircle, AlertTriangle } from "lucide-vue-next";

const realWindow = typeof globalThis !== "undefined" ? globalThis.window : undefined;
const translate = (text) => {
	return typeof realWindow !== "undefined" && typeof realWindow.__ === "function"
		? realWindow.__(text)
		: text;
};

defineProps({
	employees: { type: Array, default: () => [] },
	loading: { type: Boolean, default: false },
	startDate: { type: String, default: "" },
	endDate: { type: String, default: "" },
});

function formatDate(dateStr) {
	if (!dateStr) return "—";
	const d = new Date(dateStr);
	return d.toLocaleDateString("pl-PL", { day: "2-digit", month: "2-digit", year: "numeric" });
}
</script>
